#include<bits/stdc++.h>
using namespace std;
struct node{
    int x,y,z;
}e[200005];
int n,m;
int s[200005];
int sfind(int x) {
	if (x == s[x])	return x;
	else return s[x] = sfind(s[x]);
}
bool smerge(int i, int x) {
	int fi = sfind(i);
	int fx = sfind(x);
	if (fi == fx) {
		return false;
	}
    s[fx] = fi;
    return true;
}
bool cmp(node a,node b){
    return a.z<b.z;
}
int main() {
	cin>>n>>m;
    for(int i=1;i<=n;i++) s[i]=i;
	for(int i=1;i<=m;i++){
		cin>>e[i].x>>e[i].y>>e[i].z; 
	}
    sort(e+1,e+1+m,cmp);
    int ans=0,ans2=0;
    for(int i=1;i<=m;i++){
		if(smerge(e[i].x,e[i].y)){
            ans+=e[i].z;
            ans2+=1;
        }
	}
    if(ans2!=n-1) cout<<"orz";
    else cout<<ans;
	return 0;
}
